import type EsriColor from "../../../Color.js";
import type { JSONSupport } from "../../../core/JSONSupport.js";
import type { ColorLike } from "../../../Color.js";

/** @since 5.0 */
export interface ColorUniqueValueInfoProperties extends Partial<Pick<ColorUniqueValueInfo, "label" | "values">> {
  /**
   * The color used to represent points whose value matches `values`.
   *
   * @since 5.0
   */
  color?: ColorLike;
}

/** @since 5.0 */
export default class ColorUniqueValueInfo extends JSONSupport {
  constructor(properties?: ColorUniqueValueInfoProperties);
  /**
   * The color used to represent points whose value matches `values`.
   *
   * @since 5.0
   */
  get color(): EsriColor;
  set color(value: ColorLike);
  /**
   * Label used to describe points matched to the unique value.
   *
   * @since 5.0
   */
  accessor label: string | null | undefined;
  /**
   * A unique combination of values that will be
   *              represented with the given `color`.
   *
   * @since 5.0
   */
  accessor values: string[];
}